// Lấy item đầu tiên từ input (chỉ có 1 item)
const item = $input.item;

// Chuỗi JSON nằm trong item.json.output
let raw = item.json.output;

// 1. Loại bỏ code block ```json ... ```
raw = raw.replace(/```json/gi, "")
         .replace(/```/g, "")
         .trim();

// 2. Parse JSON string thành object
let dataArray;
try {
  dataArray = JSON.parse(raw);
} catch (e) {
  throw new Error("Không thể parse JSON từ chuỗi đầu vào: " + e.message);
}

// 3. Kiểm tra JSON phải là một array
if (!Array.isArray(dataArray)) {
  throw new Error("Dữ liệu sau parse không phải mảng.");
}

// 4. Chuẩn hóa output dạng Make yêu cầu
const output = dataArray.map(obj => ({
  json: obj   // obj phải là object → OK
}));

// 5. Trả về mảng object cho Make
return output;

// ===============================
// Utility functions
// ===============================

function mean(arr) {
  if (!arr || arr.length === 0) return 0;
  return arr.reduce((a, b) => a + b, 0) / arr.length;
}

function std(arr) {
  if (!arr || arr.length === 0) return 0;
  const m = mean(arr);
  return Math.sqrt(mean(arr.map(x => (x - m) ** 2)));
}

// Normalize input format
function normalizeQuery(query) {
  try {
    if (typeof query === "string") return JSON.parse(query);
    if (Array.isArray(query)) return query.map(i => i.json ?? i);
    if (query.json) return [query.json];
    return [query];
  } catch (e) {
    throw new Error("Invalid query format: " + e.message);
  }
}

// ===============================
// Inventory Model Formulas
// ===============================

// EOQ formula
function calcEOQ(D, K, H) {
  if (D <= 0 || K <= 0 || H <= 0) return 0;
  return Math.sqrt((2 * D * K) / H);
}

// Reorder Point
function calcROP(dailyDemand, L, sigma) {
  const z = 1.65;  // 95% service level
  const safety_stock = z * sigma * Math.sqrt(L);
  return {
    rop: dailyDemand * L + safety_stock,
    safety_stock
  };
}

// Status classification
function classifyStatus(current, optimal) {
  if (optimal <= 0) return "optimal";
  const ratio = current / optimal;
  if (ratio < 0.9) return "understock";
  if (ratio > 1.1) return "overstock";
  return "optimal";
}

// ===============================
// MAIN EXECUTION
// ===============================

try {
  const data = normalizeQuery(query);

  if (!Array.isArray(data) || data.length === 0) {
    return JSON.stringify({ error: "Input must be an array of SKU items" });
  }

  // Demand statistics per product_type
  const groups = {};
  data.forEach(sku => {
    const pt = sku.product_type ?? "Unknown";
    const sold = Number(sku.number_of_products_sold || 0);
    if (!groups[pt]) groups[pt] = [];
    groups[pt].push(sold);
  });

  const demandStats = {};
  Object.keys(groups).forEach(pt => {
    demandStats[pt] = {
      mean: mean(groups[pt]),
      std: std(groups[pt])
    };
  });

  // Global accumulators
  let totalStockValue = 0;
  let stockLevels = [];
  let turnoverValues = [];

  let outOfStockRisk = [];
  let overstockItems = [];

  const skuOptimization = [];

  // Assumptions
  const orderCost = 100; // K
  const holdingRate = 0.25; // 25% yearly

  data.forEach(raw => {
    const sku = raw.sku ?? raw.SKU ?? "";
    const productType = raw.product_type ?? "Unknown";

    const price = Number(raw.price || 0);
    const stock = Number(raw.stock_levels ?? raw.stock ?? 0);
    const sold = Number(raw.number_of_products_sold ?? 0);
    const lead = Number(raw.lead_times ?? 1);
    const shipping = Number(raw.shipping_times ?? 1);

    const dailyDemand = sold > 0 ? sold : demandStats[productType]?.mean ?? 0;
    const annualDemand = dailyDemand * 365;
    const holdingCost = price * holdingRate;

    // Calculate EOQ
    const eoq = calcEOQ(annualDemand, orderCost, holdingCost);

    // Combined lead time
    const L = Math.max(1, lead + shipping);

    // ROP + Safety Stock
    const ropData = calcROP(
      dailyDemand,
      L,
      demandStats[productType]?.std ?? 0
    );
    const reorderPoint = ropData.rop;
    const safetyStock = ropData.safety_stock;

    const optimalStock = reorderPoint + eoq / 2;

    const status = classifyStatus(stock, optimalStock);

    // Accumulate global metrics
    totalStockValue += stock * price;
    stockLevels.push(stock);

    // Inventory turnover approximation
    if (stock > 0) {
      turnoverValues.push((annualDemand || 1) / stock);
    }

    // Critical item classification
    if (status === "understock") outOfStockRisk.push(sku);
    if (status === "overstock") overstockItems.push(sku);

    skuOptimization.push({
      sku: sku,
      current_stock: Number(stock.toFixed(2)),
      optimal_stock: Number(optimalStock.toFixed(2)),
      reorder_point: Number(reorderPoint.toFixed(2)),
      eoq: Number(eoq.toFixed(2)),
      safety_stock: Number(safetyStock.toFixed(2)),
      status: status
    });
  });

  const inventorySummary = {
    total_stock_value: Number(totalStockValue.toFixed(2)),
    avg_stock_level: Number(mean(stockLevels).toFixed(2)),
    inventory_turnover_ratio: Number(mean(turnoverValues).toFixed(2))
  };

  const output = {
    inventory_summary: inventorySummary,
    sku_optimization: skuOptimization,
    critical_items: {
      out_of_stock_risk: outOfStockRisk,
      overstock_items: overstockItems
    },
    recommendations: ["AI_generated_recommendation"],
    cost_savings: "To be generated by agent"
  };

  return JSON.stringify(output);

} catch (err) {
  return JSON.stringify({ error: err.message });
}

// ===============================
// Helper functions
// ===============================
function normalizeQuery(query) {
  try {
    // Nếu là string JSON
    if (typeof query === "string") {
      const parsed = JSON.parse(query);
      if (Array.isArray(parsed)) return parsed;
      if (parsed.flat_list && Array.isArray(parsed.flat_list)) return parsed.flat_list;
      if (parsed.records && Array.isArray(parsed.records)) return parsed.records;
      return [parsed];
    }

    // Nếu là array object
    if (Array.isArray(query)) {
      return query.map(i => (i && i.json) ? i.json : i);
    }

    // Nếu là object đơn
    if (query && typeof query === "object") {
      if (Array.isArray(query.flat_list)) return query.flat_list;
      if (Array.isArray(query.records)) return query.records;
      if (query.json) return [query.json];
      return [query];
    }

    throw new Error("Invalid query format");
  } catch (e) {
    throw new Error("Invalid query format: " + e.message);
  }
}

function mean(arr) {
  if (!arr || !arr.length) return 0;
  return arr.reduce((a, b) => a + b, 0) / arr.length;
}

function groupBy(arr, key) {
  return arr.reduce((acc, item) => {
    const k = item[key] != null ? item[key] : "Unknown";
    if (!acc[k]) acc[k] = [];
    acc[k].push(item);
    return acc;
  }, {});
}

// Min-max normalize to 0–100 (higher is better if invert=false, lower is better if invert=true)
function normalizeScore(value, min, max, invert) {
  if (max === min) return 50; // tất cả giống nhau
  let score = (value - min) / (max - min); // 0–1
  if (invert) score = 1 - score;
  return score * 100;
}

// ===============================
// MAIN
// ===============================
try {
  const rows = normalizeQuery(query);

  if (!Array.isArray(rows) || rows.length === 0) {
    return JSON.stringify({ error: "Input must be a non-empty array of supplier records." });
  }

  // Chuẩn hóa dữ liệu từng bản ghi
  rows.forEach(r => {
    r.supplier_name = r.supplier_name || r.Supplier_name || r.supplier || "Unknown";
    r.location = r.location || r.Location || "";
    r.defect_rates = Number(r.defect_rates ?? r.Defect_rates ?? 0);
    r.inspection_results = r.inspection_results || r.Inspection_results || null; // có thể là "pass"/"fail" hoặc 1/0
    r.lead_times = Number(r.lead_times ?? r.Lead_times ?? 0);
    r.manufacturing_lead_time = Number(r.manufacturing_lead_time ?? r.Manufacturing_lead_time ?? 0);
    r.manufacturing_costs = Number(r.manufacturing_costs ?? r.Manufacturing_costs ?? 0);
    r.production_volumes = Number(r.production_volumes ?? r.Production_volumes ?? 0);
  });

  // Group theo supplier
  const suppliers = groupBy(rows, "supplier_name");

  // Tính global min/max cho normalizing
  const allDefects = rows.map(r => r.defect_rates).filter(v => !isNaN(v));
  const allCosts = rows.map(r => r.manufacturing_costs).filter(v => !isNaN(v));
  const allLead = rows.map(r => r.lead_times).filter(v => !isNaN(v));
  const allCapacity = rows.map(r => r.production_volumes).filter(v => !isNaN(v));

  const minDef = Math.min(...allDefects, 0);
  const maxDef = Math.max(...allDefects, 0);
  const minCost = Math.min(...allCosts, 0);
  const maxCost = Math.max(...allCosts, 0);
  const minLead = Math.min(...allLead, 0);
  const maxLead = Math.max(...allLead, 0);
  const minCap = Math.min(...allCapacity, 0);
  const maxCap = Math.max(...allCapacity, 0);

  // ================== Supplier scorecard ==================
  const scorecard = [];

  Object.keys(suppliers).forEach(name => {
    const arr = suppliers[name];
    const loc = arr[0].location || "";

    const avgDef = mean(arr.map(r => r.defect_rates));
    const passFlags = arr.map(r => {
      const v = r.inspection_results;
      if (v === "pass" || v === "PASS") return 1;
      if (v === "fail" || v === "FAIL") return 0;
      if (v === 1 || v === "1" || v === true) return 1;
      if (v === 0 || v === "0" || v === false) return 0;
      return 1; // nếu không có dữ liệu, giả định pass
    });
    const passRate = mean(passFlags);

    const avgLead = mean(arr.map(r => r.lead_times));
    const avgMfgLead = mean(arr.map(r => r.manufacturing_lead_time));
    const avgCost = mean(arr.map(r => r.manufacturing_costs));
    const totalCap = arr.reduce((s, r) => s + r.production_volumes, 0);

    // Quality score: 50% từ defect (thấp hơn tốt hơn), 50% từ pass rate
    const qualityFromDef = normalizeScore(avgDef, minDef, maxDef, true);
    const qualityFromPass = passRate * 100;
    const qualityScore = 0.5 * qualityFromDef + 0.5 * qualityFromPass;

    // Reliability: lead time + manufacturing lead time (thấp hơn tốt hơn)
    const relTime = (avgLead + avgMfgLead) / 2 || avgLead || avgMfgLead;
    const reliabilityScore = normalizeScore(relTime, minLead, maxLead, true);

    // Cost score: cost càng thấp càng tốt
    const costScore = normalizeScore(avgCost, minCost, maxCost, true);

    // Capacity score: volume càng cao càng tốt
    const capacityScore = normalizeScore(totalCap, minCap, maxCap, false);

    // Overall score: trọng số
    const overallScore =
      0.35 * qualityScore +
      0.25 * reliabilityScore +
      0.2 * costScore +
      0.2 * capacityScore;

    scorecard.push({
      supplier_name: name,
      location: loc,
      quality_score: Number(qualityScore.toFixed(1)),
      reliability_score: Number(reliabilityScore.toFixed(1)),
      cost_score: Number(costScore.toFixed(1)),
      capacity_score: Number(capacityScore.toFixed(1)),
      overall_score: Number(overallScore.toFixed(1))
    });
  });

  // Xếp hạng & rating
  scorecard.sort((a, b) => b.overall_score - a.overall_score);
  scorecard.forEach((s, idx) => {
    s.rank = idx + 1;
    const os = s.overall_score;
    let rating = "D";
    if (os >= 85) rating = "A";
    else if (os >= 70) rating = "B";
    else if (os >= 55) rating = "C";
    s.rating = rating;
  });

  // ================== Quality analysis ==================
  const avgDefectRate = mean(allDefects);
  const globalPassFlags = rows.map(r => {
    const v = r.inspection_results;
    if (v === "pass" || v === "PASS") return 1;
    if (v === "fail" || v === "FAIL") return 0;
    if (v === 1 || v === "1" || v === true) return 1;
    if (v === 0 || v === "0" || v === false) return 0;
    return 1;
  });
  const globalPassRate = mean(globalPassFlags);

  let bestQuality = null;
  let worstQuality = null;
  if (scorecard.length > 0) {
    bestQuality = scorecard.reduce((best, cur) =>
      !best || cur.quality_score > best.quality_score ? cur : best
    ).supplier_name;
    worstQuality = scorecard.reduce((worst, cur) =>
      !worst || cur.quality_score < worst.quality_score ? cur : worst
    ).supplier_name;
  }

  const quality_analysis = {
    avg_defect_rate: Number(avgDefectRate.toFixed(3)),
    pass_rate: (globalPassRate * 100).toFixed(1) + "%",
    best_supplier: bestQuality || "",
    worst_supplier: worstQuality || ""
  };

  // ================== Cost analysis ==================
  const avgCostGlobal = mean(allCosts);
  let mostCompetitive = "";
  if (scorecard.length > 0) {
    mostCompetitive = scorecard.reduce((best, cur) =>
      !best || cur.cost_score > best.cost_score ? cur : best
    ).supplier_name;
  }

  const minCostGlobal = allCosts.length ? Math.min(...allCosts) : 0;
  const maxCostGlobal = allCosts.length ? Math.max(...allCosts) : 0;

  const cost_analysis = {
    avg_manufacturing_cost: Number(avgCostGlobal.toFixed(2)),
    most_competitive: mostCompetitive,
    cost_range: `${minCostGlobal.toFixed(2)} - ${maxCostGlobal.toFixed(2)}`
  };

  // ================== Reliability analysis ==================
  const avgLeadGlobal = mean(allLead);

  let mostReliable = "";
  if (scorecard.length > 0) {
    mostReliable = scorecard.reduce((best, cur) =>
      !best || cur.reliability_score > best.reliability_score ? cur : best
    ).supplier_name;
  }

  const highRiskSuppliers = scorecard
    .filter(s => s.reliability_score < 60)
    .map(s => s.supplier_name);

  const reliability_analysis = {
    avg_lead_time: Number(avgLeadGlobal.toFixed(2)),
    most_reliable: mostReliable,
    high_risk_suppliers: highRiskSuppliers
  };

  // ================== Recommendations ==================
  const recommendations = scorecard.map(s => {
    let action = "maintain";
    if (s.rating === "B" || s.rating === "C") action = "improve";
    if (s.rating === "D") action = "replace";

    let reason = "";
    if (action === "maintain") {
      reason = "Nhà cung cấp có hiệu suất tổng thể tốt, nên tiếp tục duy trì hợp tác.";
    } else if (action === "improve") {
      reason = "Hiệu suất ở mức trung bình, cần làm việc để cải thiện chất lượng, chi phí hoặc thời gian giao hàng.";
    } else {
      reason = "Hiệu suất thấp, rủi ro cao về chất lượng hoặc giao hàng, nên cân nhắc thay thế hoặc giảm phụ thuộc.";
    }

    return {
      supplier: s.supplier_name,
      action: action,
      reason: reason
    };
  });

  const output = {
    supplier_scorecard: scorecard,
    quality_analysis,
    cost_analysis,
    reliability_analysis,
    recommendations
  };

  return JSON.stringify(output);

} catch (err) {
  return JSON.stringify({ error: err.message });
}

function normalizeQuery(query) {
  try {
    if (typeof query === "string") return JSON.parse(query);
    if (Array.isArray(query)) return query.map(i => i.json ?? i);
    if (query && typeof query === "object") {
      if (query.json) return [query.json];
      return [query];
    }
    throw new Error("Unsupported query type");
  } catch (e) {
    throw new Error("Invalid query format: " + e.message);
  }
}

function mean(arr) {
  if (!arr || !arr.length) return 0;
  return arr.reduce((a, b) => a + b, 0) / arr.length;
}

function groupBy(arr, key) {
  return arr.reduce((acc, item) => {
    const k = item[key] ?? "Unknown";
    if (!acc[k]) acc[k] = [];
    acc[k].push(item);
    return acc;
  }, {});
}

try {
  const data = normalizeQuery(query);

  if (!Array.isArray(data) || !data.length) {
    return JSON.stringify({ error: "Input must be a non-empty array." });
  }

  // --- LOGISTICS OVERVIEW ---
  const shippingTimes = data.map(i => Number(i["shipping_times"] ?? 0));
  const shippingCosts = data.map(i => Number(i["shipping_costs"] ?? 0));

  const onTimeFlags = data.map(i => {
    const lt = Number(i["lead_times"] ?? 0);
    const st = Number(i["shipping_times"] ?? 0);
    return st && lt ? (st <= lt ? 1 : 0) : 0;
  });

  const avgShippingTime = mean(shippingTimes);
  const avgShippingCost = mean(shippingCosts);
  const onTimeRate = (mean(onTimeFlags) * 100).toFixed(1) + "%";

  const logistics_overview = {
    total_shipments: Number(data.length),
    avg_shipping_time: Number(avgShippingTime.toFixed(2)),
    avg_shipping_cost: Number(avgShippingCost.toFixed(2)),
    on_time_delivery_rate: onTimeRate
  };

  // --- CARRIER PERFORMANCE ---
  const carriers = groupBy(data, "shipping_carriers");

  const carrier_performance = Object.keys(carriers).map(carrier => {
    const arr = carriers[carrier];

    const avg_time = mean(arr.map(i => Number(i["shipping_times"] ?? 0)));
    const avg_cost = mean(arr.map(i => Number(i["shipping_costs"] ?? 0)));
    const volume = arr.reduce(
      (s, i) => s + Number(i["number_of_products_sold"] ?? 0),
      0
    );

    const reliability = mean(
      arr.map(i =>
        Number(i["shipping_times"] ?? 0) <= Number(i["lead_times"] ?? 0)
          ? 1
          : 0
      )
    );

    return {
      carrier: String(carrier),
      avg_time: Number(avg_time.toFixed(2)),
      avg_cost: Number(avg_cost.toFixed(2)),
      reliability_score: Number((reliability * 100).toFixed(1)),
      volume: Number(volume)
    };
  });

  // --- ROUTE ANALYSIS ---
  const routes = groupBy(data, "routes");

  const route_analysis = Object.keys(routes).map(route => {
    const arr = routes[route];

    const avg_time = mean(arr.map(i => Number(i["shipping_times"] ?? 0)));
    const avg_cost = mean(arr.map(i => Number(i["shipping_costs"] ?? 0)));
    const eff = avg_time > 0 ? (1 / avg_time) * 100 : 0;

    return {
      route: String(route),
      avg_cost: Number(avg_cost.toFixed(2)),
      avg_time: Number(avg_time.toFixed(2)),
      efficiency_score: Number(eff.toFixed(2))
    };
  });

  // --- TRANSPORTATION MODES ---
  const modes = groupBy(data, "transportation_modes");

  const transportation_mode_comparison = Object.keys(modes).map(mode => {
    const arr = modes[mode];

    const avg_time = mean(arr.map(i => Number(i["shipping_times"] ?? 0)));
    const avg_cost = mean(arr.map(i => Number(i["shipping_costs"] ?? 0)));

    return {
      mode: String(mode),
      cost_efficiency:
        avg_cost < logistics_overview.avg_shipping_cost ? "good" : "poor",
      time_efficiency:
        avg_time < logistics_overview.avg_shipping_time ? "fast" : "slow",
      usage_rate: ((arr.length / data.length) * 100).toFixed(1) + "%"
    };
  });

  // --- BOTTLENECKS ---
  const bottlenecks = [];

  const onTimeNum = Number(
    logistics_overview.on_time_delivery_rate.replace("%", "")
  );
  if (onTimeNum < 85) {
    bottlenecks.push("Overall on-time delivery rate is below 85%.");
  }

  carrier_performance.forEach(c => {
    if (c.reliability_score < 80) {
      bottlenecks.push(
        `Carrier ${c.carrier} has low reliability (${c.reliability_score}%).`
      );
    }
  });

  // --- RECOMMENDATIONS ---
  const recommendations = [
    "Investigate low-reliability carriers and redistribute volume.",
    "Use routes with higher efficiency scores for urgent shipments.",
    "Review transportation modes with poor cost or time efficiency."
  ];

  // FINAL OUTPUT
  const output = {
    logistics_overview,
    carrier_performance,
    route_analysis,
    transportation_mode_comparison,
    bottlenecks,
    recommendations
  };

  return JSON.stringify(output);

} catch (err) {
  return JSON.stringify({ error: err.message });
}

// =====================
// Utility functions
// =====================

function mean(arr) {
  if (!arr || !arr.length) return 0;
  return arr.reduce((a, b) => a + b, 0) / arr.length;
}

function std(arr) {
  if (!arr || !arr.length) return 0;
  const m = mean(arr);
  return Math.sqrt(mean(arr.map(x => (x - m) ** 2)));
}

function confidence(arr) {
  if (!arr || !arr.length) return "low";
  const m = mean(arr);
  if (m === 0 || isNaN(m)) return "low";
  const cv = std(arr) / m;
  if (cv < 0.3) return "high";
  if (cv < 0.6) return "medium";
  return "low";
}

// =====================
// FIX NORMALIZER FOR YOUR WORKFLOW
// =====================

function normalizeQuery(q) {
  if (!q) return [];

  // CASE 1: q là STRING chứa JSON
  if (typeof q === "string") {
    try {
      const parsed = JSON.parse(q);

      // dạng { query: [...] }
      if (parsed.query && Array.isArray(parsed.query)) {
        return parsed.query;
      }

      // dạng [...]
      if (Array.isArray(parsed)) return parsed;

      return [];
    } catch (e) {
      return [];
    }
  }

  // CASE 2: object có field query: [...]
  if (typeof q === "object") {
    if (Array.isArray(q.query)) return q.query;
    if (Array.isArray(q)) return q;
  }

  return [];
}

// =====================
// Forecast per product type
// =====================

function forecastByType(df) {
  const groups = {};
  const output = [];

  df.forEach(item => {
    const type = item.product_type || "unknown";
    if (!groups[type]) groups[type] = [];
    groups[type].push(item);
  });

  for (const type in groups) {
    const items = groups[type];
    const sales = items.map(x => Number(x.number_of_products_sold) || 0);

    const avg = mean(sales);
    const forecast30 = avg * 30;

    let trend = "stable";
    if (sales.length >= 2) {
      trend = sales[sales.length - 1] > sales[0] ? "increasing" : "decreasing";
    }

    output.push({
      product_type: type,
      current_avg_sales: Number(avg.toFixed(2)),
      forecasted_demand: Number(forecast30.toFixed(2)),
      trend,
      confidence: confidence(sales)
    });
  }

  return output;
}

// =====================
// High vs Low demand
// =====================

function splitHighLow(df) {
  const sales = df.map(x => Number(x.number_of_products_sold) || 0);
  const avg = mean(sales);

  return {
    high: [...new Set(df.filter(x => x.number_of_products_sold > avg).map(x => x.product_type))],
    low: [...new Set(df.filter(x => x.number_of_products_sold <= avg).map(x => x.product_type))]
  };
}

// =====================
// Summary
// =====================

function summary(analysis) {
  const total = analysis.reduce((s, x) => s + x.forecasted_demand, 0);
  const inc = analysis.filter(x => x.trend === "increasing").length;
  const dec = analysis.filter(x => x.trend === "decreasing").length;

  let trend = "stable";
  if (inc > dec) trend = "increasing";
  else if (dec > inc) trend = "decreasing";

  return {
    next_30_days_demand: String(Math.round(total)),
    confidence_level: "medium",
    trend
  };
}

// =====================
// MAIN
// =====================

try {
  const df = normalizeQuery(query);

  const analysis = forecastByType(df);
  const { high, low } = splitHighLow(df);

  const result = {
    forecast_summary: summary(analysis),
    product_analysis: analysis,
    high_demand_products: high,
    low_demand_products: low
  };

  return JSON.stringify(result);

} catch (err) {
  return JSON.stringify({ error: err.message });
}

