const merged = $input.all();

/**
 * Tìm object CHA có chứa key con.
 */
function findParentWithKey(obj, key) {
  if (!obj || typeof obj !== "object") return null;

  for (const prop in obj) {
    const value = obj[prop];

    if (prop === key) {
      // trả về object CHA chứa key
      return obj;
    }

    if (typeof value === "object") {
      const found = findParentWithKey(value, key);
      if (found) return found;
    }
  }
  return null;
}

